  tight:   '-0.025em',
  normal:  '0em',
  wide:    '0.025em',
  wider:   '0.05em',
  widest:  '0.1em',
} as const;

// ─── Semantic Typography Presets ─────────────────────────────────────────────

export const text = {
  // Headings
  h1: {
    fontFamily: fontFamily.display,
    fontSize: fontSize['4xl'].size,
